package job

import (
	"context"
	"math/big"
	"testing"
	"time"

	ethereum "github.com/ethereum/go-ethereum"
	"github.com/ethereum/go-ethereum/accounts/abi"
	"github.com/ethereum/go-ethereum/common"

	"cre-keeper/internal/chain"
)

// RedemptionProbe creation bytecode (forge solc 0.8.24) — verbatim from the CRE-02
// ticket / cre/keeper/RedemptionProbe.sol. The probe returns itself for
// queue()/zipUSD()/usdc(), returns rqSafe (settable) for juniorTrancheSafe(),
// returns scripted scalars for scaleUp()/totalPending()/reservedAssets()/
// balanceOf(address)/maxWithdraw(address), and RECORDS the ordered (selector, arg)
// of every settleEpoch()/claim(uint256)/requestRedeem(uint256) leg the Runner
// submits.
const redemptionProbeBytecode = ""

// TestRedemptionJob_SimEndToEnd deploys the RedemptionProbe, seeds its scripted
// views so all three legs fire, runs the RedemptionJob through the Runner, and
// asserts the probe recorded the EXACT ordered (selector, arg) sequence.
//
// Seeds: scaleUp=1e12, totalPending=3e12, reservedAssets=0, bal=1e18,
// claimable=5, rqSafe=probe. The probe returns itself for queue/zipUSD/usdc and
// rqSafe==probe, so both balanceOf reads hit the single bal slot — bal large
// opens the settle gate (freeUsdc>0) AND supplies idleZip>=gap, so escrow floors
// to the gap. targetPending=10e12 ⇒ escrow == floorToUnit(10e12−3e12,1e12)==7e12.
func TestRedemptionJob_SimEndToEnd(t *testing.T) {
	env := newSimEnv(t, false) // self-deploy; do NOT deploy the unrelated OnlyOperatorProbe.
	probe := env.deployProbe(env.sim.Client(), redemptionProbeBytecode)

	seed := func(label string, data []byte) {
		if _, err := env.chain.Submit(context.Background(), chain.Action{Label: label, To: probe, Data: data}); err != nil {
			t.Fatalf("%s submit: %v", label, err)
		}
	}
	if err := env.chain.ResyncNonce(context.Background()); err != nil {
		t.Fatalf("resync: %v", err)
	}
	seed("setScaleUp", chain.PackUintCall("setScaleUp(uint256)", bigStr("1000000000000")))
	seed("setTotalPending", chain.PackUintCall("setTotalPending(uint256)", bigStr("3000000000000")))
	seed("setReservedAssets", chain.PackUintCall("setReservedAssets(uint256)", big.NewInt(0)))
	seed("setBal", chain.PackUintCall("setBal(uint256)", bigStr("1000000000000000000")))
	seed("setClaimable", chain.PackUintCall("setClaimable(uint256)", big.NewInt(5)))
	rqSel := sel("setRqSafe(address)")
	seed("setRqSafe", append(rqSel[:], encodeAddr(probe)...))

	j := NewRedemptionJob(probe, bigStr("10000000000000")) // targetPending = 10e12

	runner := NewRunner(env.chain, []Job{j}, 10*time.Millisecond, quietLogger())
	ctx, cancel := context.WithCancel(context.Background())
	doneRun := make(chan struct{})
	go func() { runner.Run(ctx); close(doneRun) }()

	waitFor(t, func() bool {
		n, err := chain.CallUint(context.Background(), env.chain, probe, "recordCount()")
		return err == nil && n.Uint64() >= 3
	})
	cancel()
	<-doneRun

	n, err := chain.CallUint(context.Background(), env.chain, probe, "recordCount()")
	if err != nil {
		t.Fatalf("recordCount: %v", err)
	}
	if n.Uint64() != 3 {
		t.Fatalf("recordCount = %d, want 3", n.Uint64())
	}

	type want struct {
		sig string
		a0  *big.Int
	}
	wants := []want{
		{"settleEpoch()", nil}, // a0 ignored
		{"claim(uint256)", big.NewInt(5)},
		{"requestRedeem(uint256)", floorToUnit(bigStr("7000000000000"), bigStr("1000000000000"))}, // 7e12
	}

	for i, w := range wants {
		gotSel, a0 := readRedemptionRecord(t, env.chain, probe, i)
		if gotSel != sel4(w.sig) {
			t.Errorf("record[%d] selector = %x, want %x (%s)", i, gotSel, sel4(w.sig), w.sig)
		}
		if w.a0 != nil && a0.Cmp(w.a0) != 0 {
			t.Errorf("record[%d] (%s) a0 = %s, want %s", i, w.sig, a0, w.a0)
		}
	}
}

// readRedemptionRecord calls probe.record(i) → (bytes4 sel, uint256 a0). The
// probe's record is a 2-field tuple (NOT StrikeLoop's 4-field shape), so this is a
// purpose-built local decoder, not readRecord.
func readRedemptionRecord(t *testing.T, r chain.Reader, probe common.Address, i int) ([4]byte, *big.Int) {
	t.Helper()
	data := chain.PackUintCall("record(uint256)", big.NewInt(int64(i)))
	out, err := r.CallContract(context.Background(), ethereum.CallMsg{To: &probe, Data: data}, nil)
	if err != nil {
		t.Fatalf("record(%d): %v", i, err)
	}
	b4, _ := abi.NewType("bytes4", "", nil)
	u, _ := abi.NewType("uint256", "", nil)
	vals, err := abi.Arguments{{Type: b4}, {Type: u}}.Unpack(out)
	if err != nil {
		t.Fatalf("decode record(%d): %v", i, err)
	}
	return vals[0].([4]byte), vals[1].(*big.Int)
}
